def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = 0 if item == 0 else np.inf
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if ratio < 0:
            priorities[i] = np.inf
            continue
        if item == 0:
            priorities[i] = 0
            continue
        score = 0.0
        complexity = 1.0
        decay = 1.0
        bonus = 0.0
        penalty = 0.0
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio < 0.5:
            for a in range(1, 11):
                if a % 2 == 0:
                    score += ((ratio ** a) / (a + 1)) * np.sin(a * ratio)
                else:
                    score -= ((ratio ** a) / (a + 1)) * np.cos(a * ratio / 2)
            complexity = np.exp(-ratio * 5)
            decay = 1 / (1 + np.sqrt(capacity))
            score = abs(score) * 20 * complexity * decay
            if ratio < 0.1:
                bonus = sum((ratio ** b) / (b ** 2 + 1) for b in range(1, 6))
                score -= bonus * 5
        elif 0.5 <= ratio < 1.5:
            for b in range(1, 15):
                term = ((-1) ** b) * (ratio ** b) / (b + 1)
                penalty += np.log1p(abs(term)) if term != 0 else 0
                if b % 3 == 0:
                    bonus += np.sqrt(abs(term))
            complexity = 1 + np.sin(ratio * np.pi / 2)
            score = penalty * 10 + bonus * 4
            score /= complexity
            if ratio > 1.2:
                score += (ratio - 1.2) ** 3 * 15
        elif 1.5 <= ratio < 3:
            penalty = 0
            for c in range(1, 8):
                factor = c ** 2 + 1
                term = (ratio ** c) / factor
                penalty += (-1) ** c * np.exp(-term)
            for d in range(1, 6):
                decay *= (1 - 1 / (ratio + d + 1))
            complexity = np.log(ratio + 2)
            score = abs(penalty) * complexity * decay * 25
            if item > 2 * capacity:
                score *= 1.5
            else:
                score *= 2
            if int(capacity) % 2 == 0:
                score *= 0.9
        else:
            penalty = 0
            for e in range(1, 5):
                for f in range(1, 5):
                    term = ((ratio / (e + f)) ** (e + f)) / (e * f + 1)
                    penalty += term if (e + f) % 2 == 0 else -term
            decay = np.prod([1 - 1 / (ratio + k + 0.5) for k in range(1, 5)])
            complexity = ratio ** 0.8
            score = abs(penalty) * complexity * decay * 30
            if item > capacity * 5:
                score *= 3
            else:
                score *= 1.2
        adjustment = 1.0
        if capacity < 10:
            adjustment *= (1 + (10 - capacity) / 50)
        if item > capacity * 1.5:
            adjustment *= (1 + (item - capacity) / (capacity * 10))
        if ratio > 4:
            adjustment *= 0.8
        priorities[i] = score * adjustment
    return priorities
